transforms.result:
.designer-wrap {
  width: 100%;
  height: 100vh;
  overflow: hidden;

  .el-card {
    padding: 10px !important;
  }

  .designer-base-info {
    margin: 0 auto;
    padding: 24px 0;
    height: 100%;
    text-align: center;
    overflow-y: auto;
    background-color: #f2f3f5;

    .base-info-panel {
      display: inline-block;
      width: 1128px;
      padding: 24px 288px;
      background-color: #fff;
      text-align: left;
    }
  }

  .designer-content-box {
    width: 100%;
    height: calc(100vh - 50px);
    overflow: hidden;

    .sh-flow-editor-wrap {
      width: 100%;
      height: 100%;
      background-color: #f2f3f5;
      position: relative;

      &::before {
        display: table;
        content: '';
      }

      .sh-flow-editor-container {
        display: -webkit-box;
        display: -ms-flexbox;
        display: flex;
        width: 100%;
        height: 100%;
        overflow: scroll;

        .sh-flow-editor-content {
          margin: 30px auto;

          .flow-row-container,
          .flow-row {
            display: -webkit-box;
            display: -ms-flexbox;
            display: flex;
            -webkit-box-orient: vertical;
            -webkit-box-direction: normal;
            -ms-flex-direction: column;
            flex-direction: column;
            -webkit-box-flex: 1;
            -ms-flex-positive: 1;
            flex-grow: 1;
          }

          .flow-row {
            -webkit-box-align: center;
            -ms-flex-align: center;
            align-items: center;
            position: relative;

            .flow-box {
              -webkit-box-flex: 1;
              -ms-flex-positive: 1;
              flex-grow: 1;
              padding: 0 50px;
              position: relative;

              &::before {
                content: '';
                position: absolute;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                margin: auto;
                width: 2px;
                height: 100%;
                background-color: var(--star-horse-light-gray);
              }

              .node-start-btn {
                padding-bottom: 20px;
              }

              .after-node-btn {
                padding: 20px 0 35px;
                position: relative;
                text-align: center;

                img {
                  cursor: pointer;
                }
              }
            }

            .flow-item {
              padding-top: 0;

              .node-start {
                position: relative;
                display: -webkit-box;
                display: -ms-flexbox;
                display: flex;
                z-index: 2;
                -webkit-box-pack: center;
                -ms-flex-pack: center;
                justify-content: center;
                -webkit-box-align: center;
                -ms-flex-align: center;
                align-items: center;
                width: 60px;
                height: 60px;
                border-radius: 60px;
                color: #f8f8fa;
                background-image: -webkit-gradient(linear, left top, right top, from(#ff6a00), to(#f78b3e)),
                -webkit-gradient(linear, left top, left bottom, from(#ff6a00), to(#ff6a00));
                background-image: -webkit-linear-gradient(left, #ff6a00, #f78b3e), -webkit-linear-gradient(#ff6a00, #ff6a00);
                background-image: -o-linear-gradient(left, #ff6a00 0, #f78b3e 100%), -o-linear-gradient(#ff6a00, #ff6a00);
                background-image: linear-gradient(90deg, #ff6a00, #f78b3e), linear-gradient(#ff6a00, #ff6a00);
                background-blend-mode: normal, normal;
                -webkit-box-shadow: 0 2px 10px 0 rgba(255, 107, 2, 50%);
                box-shadow: 0 2px 10px 0 rgba(255, 107, 2, 50%);
                font-size: 18px;
              }

              .node-temmi {
                cursor: pointer;
                background-image: -webkit-gradient(linear, left top, right top, from(#ff4056), to(#ff4056)),
                -webkit-gradient(linear, left top, left bottom, from(#ff6173), to(#ff6173));
                background-image: -webkit-linear-gradient(left, #ff4056, #ff4056), -webkit-linear-gradient(#ff6173, #ff6173);
                background-image: -o-linear-gradient(left, #ff4056 0, #ff4056 100%), -o-linear-gradient(#ff6173, #ff6173);
                background-image: linear-gradient(90deg, #ff4056, #ff4056), linear-gradient(#ff6173, #ff6173);

                &:hover .close-icon {
                  display: -webkit-box;
                  display: -ms-flexbox;
                  display: flex;
                }

                .close-icon {
                  position: absolute;
                  display: none;
                  -webkit-box-pack: center;
                  -ms-flex-pack: center;
                  justify-content: center;
                  -webkit-box-align: center;
                  -ms-flex-align: center;
                  align-items: center;
                  top: -2px;
                  left: -5px;
                  width: 20px;
                  height: 20px;
                  background: #9e9e9e;
                  color: #fff;
                  font-size: 14px;
                  border-radius: 16px;

                  .close-icon:hover {
                    background: var(--el-color-danger);
                  }
                }
              }

              .flow-node-box {
                cursor: pointer;
                // width: 220px;
                // height: 118px;
                width: 210px;
                height: 100px;
                background-color: #fff;
                -webkit-box-shadow: 0 2px 6px 0 rgba(75, 82, 94, 0.2);
                box-shadow: 0 2px 6px 0 rgba(75, 82, 94, 0.2);
                border-radius: 4px;
                position: relative;
                -webkit-box-sizing: border-box;
                box-sizing: border-box;

                .node-sp,
                .node-start-bg {
                  background-image: -webkit-gradient(linear, left top, right top, from(#ff6a00), to(#f78b3e)),
                  -webkit-gradient(linear, left top, left bottom, from(#ff6a00), to(#ff6a00));
                  background-image: -webkit-linear-gradient(left, #ff6a00, #f78b3e), -webkit-linear-gradient(#ff6a00, #ff6a00);
                  background-image: -o-linear-gradient(left, #ff6a00 0, #f78b3e 100%), -o-linear-gradient(#ff6a00, #ff6a00);
                  background-image: linear-gradient(90deg, #ff6a00, #f78b3e), linear-gradient(#ff6a00, #ff6a00);
                }

                .node-launch,
                .node-task {
                  background-image: -webkit-gradient(linear, left top, right top, from(#E872B7), to(#a9b4cd)),
                  -webkit-gradient(linear, left top, left bottom, from(#E872B7), to(#a9b4cd));
                  background-image: -webkit-linear-gradient(left, #E872B7, #a9b4cd), -webkit-linear-gradient(#E872B7, #a9b4cd);
                  background-image: -o-linear-gradient(left, #E872B7 0, #a9b4cd 100%), -o-linear-gradient(#E872B7, #a9b4cd);
                  background-image: linear-gradient(90deg, #E872B7, #a9b4cd), linear-gradient(#E872B7, #a9b4cd);
                }

                .node-timer {
                  background-image: -webkit-gradient(linear, left top, right top, from(#a9b4cd), to(#E872B7)),
                  -webkit-gradient(linear, left top, left bottom, from(#a9b4cd), to(#E872B7));
                  background-image: -webkit-linear-gradient(left, #a9b4cd, #E872B7), -webkit-linear-gradient(#a9b4cd, #E872B7);
                  background-image: -o-linear-gradient(left, #a9b4cd 0, #E872B7 100%), -o-linear-gradient(#a9b4cd, #E872B7);
                  background-image: linear-gradient(90deg, #a9b4cd, #E872B7), linear-gradient(#a9b4cd, #E872B7);
                }

                .node-sub-branch {
                  background-image: -webkit-gradient(linear, left top, right top, from(#4f9593), to(#61f64a)),
                  -webkit-gradient(linear, left top, left bottom, from(#4f9593), to(#61f64a));
                  background-image: -webkit-linear-gradient(left, #4f9593, #61f64a), -webkit-linear-gradient(#4f9593, #61f64a);
                  background-image: -o-linear-gradient(left, #4f9593 0, #61f64a 100%), -o-linear-gradient(#4f9593, #61f64a);
                  background-image: linear-gradient(90deg, #4f9593, #61f64a), linear-gradient(#4f9593, #61f64a);
                }

                .node-cc {
                  background-image: -webkit-gradient(linear, left top, right top, from(#268bfb -16.37%), to(#33e1ae 137.34%)),
                  -webkit-gradient(linear, left top, left bottom, from(#ff6a00), to(#ff6a00));
                  background-image: -webkit-linear-gradient(left, #268bfb -16.37%, #33e1ae 137.34%), -webkit-linear-gradient(#ff6a00, #ff6a00);
                  background-image: -o-linear-gradient(left, #268bfb -16.37% 0, #33e1ae 137.34%), -o-linear-gradient(#ff6a00, #ff6a00);
                  background-image: linear-gradient(90deg, #268bfb -16.37%, #33e1ae 137.34%), linear-gradient(#ff6a00, #ff6a00);
                }

                .node-tz {
                  background-image: -webkit-gradient(linear, left top, right top, from(#498ff2), to(#6da4f2)),
                  -webkit-gradient(linear, left top, left bottom, from(#9d5eb6), to(#6e098a));
                  background-image: -webkit-linear-gradient(left, #498ff2, #6da4f2), -webkit-linear-gradient(#ff6a00, #ff6a00);
                  background-image: -o-linear-gradient(left, #498ff2 0, #6da4f2 100%), -o-linear-gradient(#ff6a00, #ff6a00);
                  background-image: linear-gradient(90deg, #498ff2, #6da4f2), linear-gradient(#ff6a00, #ff6a00);
                }

                .node-fill {
                  background-image: -webkit-gradient(linear, left top, right top, from(#29cc80), to(#5ccc98)),
                  -webkit-gradient(linear, left top, left bottom, from(#29cc80), to(#29cc80));
                  background-image: -webkit-linear-gradient(left, #29cc80, #5ccc98), -webkit-linear-gradient(#29cc80, #29cc80);
                  background-image: -o-linear-gradient(left, #29cc80 0, #5ccc98 100%), -o-linear-gradient(#29cc80, #29cc80);
                  background-image: linear-gradient(90deg, #29cc80, #5ccc98), linear-gradient(#29cc80, #29cc80);
                }

                .node-transact {
                  background-image: -webkit-gradient(linear, left top, right top, from(#935af6), to(#f65ac2)),
                  -webkit-gradient(linear, left top, left bottom, from(#935af6), to(#935af6));
                  background-image: -webkit-linear-gradient(left, #935af6, #f65ac2), -webkit-linear-gradient(#935af6, #935af6);
                  background-image: -o-linear-gradient(left, #935af6 0, #f65ac2 100%), -o-linear-gradient(#935af6, #935af6);
                  background-image: linear-gradient(90deg, #935af6, #f65ac2), linear-gradient(#935af6, #935af6);
                }

                .node-delete {
                  background-image: -webkit-gradient(linear, left top, right top, from(#aaaab3), to(#aaaab3)),
                  -webkit-gradient(linear, left top, left bottom, from(#c4c4cc), to(#c4c4cc));
                  background-image: -webkit-linear-gradient(left, #aaaab3, #aaaab3), -webkit-linear-gradient(#c4c4cc, #c4c4cc);
                  background-image: -o-linear-gradient(left, #aaaab3 0, #aaaab3 100%), -o-linear-gradient(#c4c4cc, #c4c4cc);
                  background-image: linear-gradient(90deg, #aaaab3, #aaaab3), linear-gradient(#c4c4cc, #c4c4cc);
                }

                .node-handle {
                  background-image: -webkit-gradient(linear, left top, right top, from(#ff9313), to(#faab4b)),
                  -webkit-gradient(linear, left top, left bottom, from(#ff6a00), to(#ff6a00));
                  background-image: -webkit-linear-gradient(left, #ff9313, #faab4b), -webkit-linear-gradient(#ff6a00, #ff6a00);
                  background-image: -o-linear-gradient(left, #ff9313 0, #faab4b 100%), -o-linear-gradient(#ff6a00, #ff6a00);
                  background-image: linear-gradient(90deg, #ff9313, #faab4b), linear-gradient(#ff6a00, #ff6a00);
                }

                //  进行中
                .node-status-current {
                  background-image: -webkit-gradient(linear, left top, right top, from(#1890ff), to(#1890ff)),
                  -webkit-gradient(linear, left top, left bottom, from(#1890ff), to(#1890ff));
                  background-image: -webkit-linear-gradient(left, #1890ff, #1890ff), -webkit-linear-gradient(#909399, #909399);
                  background-image: -o-linear-gradient(left, #1890ff 0, #1890ff 100%), -o-linear-gradient(#909399, #909399);
                  background-image: linear-gradient(90deg, #1890ff, #1890ff), linear-gradient(#1890ff, #1890ff);
                }

                //  未进行
                .node-status-not {
                  background-image: -webkit-gradient(linear, left top, right top, from(#909399), to(#909399)),
                  -webkit-gradient(linear, left top, left bottom, from(#909399), to(#909399));
                  background-image: -webkit-linear-gradient(left, #909399, #909399), -webkit-linear-gradient(#909399, #909399);
                  background-image: -o-linear-gradient(left, #909399 0, #909399 100%), -o-linear-gradient(#909399, #909399);
                  background-image: linear-gradient(90deg, #909399, #909399), linear-gradient(#909399, #909399);
                }

                //  已完成
                .node-status-complete {
                  background-image: -webkit-gradient(linear, left top, right top, from(#20b2aa), to(#20b2aa)),
                  -webkit-gradient(linear, left top, left bottom, from(#20b2aa), to(#20b2aa));
                  background-image: -webkit-linear-gradient(left, #20b2aa, #20b2aa), -webkit-linear-gradient(#20b2aa, #20b2aa);
                  background-image: -o-linear-gradient(left, #20b2aa 0, #20b2aa 100%), -o-linear-gradient(#20b2aa, #20b2aa);
                  background-image: linear-gradient(90deg, #20b2aa, #20b2aa), linear-gradient(#20b2aa, #20b2aa);
                }

                .node-name {
                  padding: 5px;
                  font-size: 14px;
                  -webkit-box-sizing: border-box;
                  box-sizing: border-box;
                  border-radius: 4px 4px 0 0;
                  height: 34px;
                  -webkit-box-pack: justify;
                  -ms-flex-pack: justify;
                  justify-content: space-between;
                  display: -webkit-box;
                  display: -ms-flexbox;
                  display: flex;
                  -webkit-box-align: center;
                  -ms-flex-align: center;
                  align-items: center;
                  color: #fff;
                  background-color: #ff6a00;

                  .node-name-title {
                    font-weight: bold;
                    height: 100%;
                    display: flex;
                    align-items: center;
                    flex: 1;

                    span {
                      display: block;
                      width: 100%;
                      height: 100%;

                    }
                  }

                  .node-name-level {
                    text-align: right;
                  }

                  &:before {
                    content: "";
                    position: absolute;
                    top: -8px;
                    left: 50%;
                    transform: translate(-50%);
                    width: 0;
                    border-style: solid;
                    border-width: 8px 6px 4px;
                    border-color: rgb(202, 202, 202) transparent transparent;
                    /*  background: rgb(239,239,239)*/
                  }
                }

                .node-main {
                  -webkit-box-align: center;
                  -ms-flex-align: center;
                  align-items: center;
                  height: calc(100% - 44px);
                  border-top: none;
                  -webkit-box-sizing: border-box;
                  box-sizing: border-box;
                  display: -webkit-box;
                  display: -ms-flexbox;
                  display: flex;
                  padding-left: 16px;
                  padding-right: 16px;
                  white-space: nowrap;
                  overflow: hidden;
                  -o-text-overflow: ellipsis;
                  text-overflow: ellipsis;
                  color: #575757;
                  font-size: 14px;

                  span {
                    overflow: hidden;
                    text-overflow: ellipsis;
                  }

                  .hint-title {
                    color: #ff6a00;
                    font-size: 12px;
                  }
                }

                &.has-error {
                  border: 1px solid #ff5b4c;
                  box-shadow: 0 0 3px 0 #ff5b4c;
                }

                .node-error {
                  position: absolute;
                  right: -40px;
                  top: 32px;
                  font-size: 32px;
                  color: #ff5b4c;
                }

                &:hover .close-icon {
                  display: -webkit-box;
                  display: -ms-flexbox;
                  display: flex;
                }

                .close-icon {
                  position: absolute;
                  display: none;
                  -webkit-box-pack: center;
                  -ms-flex-pack: center;
                  justify-content: center;
                  -webkit-box-align: center;
                  -ms-flex-align: center;
                  align-items: center;
                  top: -5px;
                  left: -5px;
                  width: 20px;
                  height: 20px;
                  background: #9e9e9e;
                  color: #fff;
                  font-size: 14px;
                  border-radius: 16px;

                  &:hover {
                    background: var(--el-color-danger);
                  }
                }
              }

              .flow-branch-suggest {
                cursor: pointer;
                width: 210px;
                height: 60px;
                background-color: #fff;
                -webkit-box-shadow: 0 2px 6px 0 rgba(75, 82, 94, 20%);
                box-shadow: 0 2px 6px 0 rgba(75, 82, 94, 20%);
                border-radius: 4px;
                position: relative;
                -webkit-box-sizing: border-box;
                box-sizing: border-box;

                &:hover .close-icon {
                  display: -webkit-box;
                  display: -ms-flexbox;
                  display: flex;
                }

                .node-name {
                  padding: 15px;
                  margin-right: -1px;
                  font-size: 14px;
                  font-weight: 700;
                  color: #575757;
                  background-color: #fff;
                  border: none !important;
                  height: 60px;
                  -webkit-box-sizing: border-box;
                  box-sizing: border-box;
                  border-radius: 4px 4px 0 0;
                  -webkit-box-pack: center;
                  -ms-flex-pack: center;
                  -webkit-box-align: center;
                  -ms-flex-align: center;
                  justify-content: center;
                  display: flex;
                  align-items: center;

                  span {
                    text-overflow: ellipsis;
                    overflow: hidden;
                    white-space: nowrap;
                  }
                }

                .close-icon {
                  position: absolute;
                  display: none;
                  -webkit-box-pack: center;
                  -ms-flex-pack: center;
                  justify-content: center;
                  -webkit-box-align: center;
                  -ms-flex-align: center;
                  align-items: center;
                  top: -5px;
                  left: -5px;
                  width: 20px;
                  height: 20px;
                  background: #9e9e9e;
                  color: #fff;
                  font-size: 14px;
                  border-radius: 16px;

                  &:hover {
                    background: red;
                  }
                }
              }

              .flow-node-box,
              .flow-branch-suggest {
                /* 删除遮罩 */
                .node-delete-layer {
                  position: absolute;
                  width: 100%;
                  height: 100%;
                  left: 0;
                  top: 0;
                  display: flex;
                  justify-content: center;
                  align-items: center;
                  background: rgba(0, 0, 0, 0.7);
                  border-radius: 4px;

                  button {
                    margin: 10px;
                  }

                  .node-delete-cancel {
                    color: #fff;
                    border-color: #fff;
                  }

                  .ant-btn-ghost {
                    background-color: initial;
                  }
                }
              }
            }

            // 选中
            .flow-item-active {
              -webkit-box-shadow: 0 3px 30px 0 rgba(255, 106, 0, 75%);
              box-shadow: 0 3px 30px 0 rgba(255, 106, 0, 75%);
            }

            // 分支节点
            .flow-branch {
              position: relative;
              display: -webkit-box;
              display: -ms-flexbox;
              display: flex;
              -webkit-box-orient: horizontal;
              -webkit-box-direction: normal;
              -ms-flex-direction: row;
              flex-direction: row;
              border-top: 2px solid var(--star-horse-light-gray);
              border-bottom: 2px solid var(--star-horse-light-gray);

              .clear-left-border,
              .clear-right-border {
                position: absolute;
                top: 0;
                bottom: 0;
                width: 100%;
              }

              .branch-node {
                position: absolute;
                top: 0;
                left: 50%;
                z-index: 2;
                -webkit-transform: translate(-50%, -50%);
                -ms-transform: translate(-50%, -50%);
                transform: translate(-50%, -50%);
                cursor: pointer;
              }

              .meet-node {
                position: absolute;
                bottom: 0;
                left: 50%;
                z-index: 2;
                -webkit-transform: translate(-50%, 50%);
                -ms-transform: translate(-50%, 50%);
                transform: translate(-50%, 50%);
              }

              .flow-col {
                display: -webkit-box;
                display: -ms-flexbox;
                display: flex;
                -webkit-box-orient: vertical;
                -webkit-box-direction: normal;
                -ms-flex-direction: column;
                flex-direction: column;
                position: relative;

                .clear-left-border {
                  left: 0;

                  &::before {
                    content: '';
                    position: absolute;
                    left: 0;
                    top: -5px;
                    width: 50%;
                    background: #f2f3f5;
                    height: 10px;
                  }

                  &::after {
                    content: '';
                    position: absolute;
                    left: 0;
                    bottom: -5px;
                    width: 50%;
                    background: #f2f3f5;
                    height: 10px;
                  }
                }

                .clear-right-border {
                  right: 0;

                  &::before {
                    content: '';
                    position: absolute;
                    right: -0.5px;
                    top: -5px;
                    width: 50%;
                    background: #f2f3f5;
                    height: 10px;
                  }

                  &::after {
                    content: '';
                    position: absolute;
                    right: -0.5px;
                    bottom: -5px;
                    width: 50%;
                    background: #f2f3f5;
                    height: 10px;
                  }
                }

                .flow-row {
                  -webkit-box-flex: 1;
                  -ms-flex-positive: 1;
                  flex-grow: 1;
                }

                .flow-node-branch {
                  /* padding-bottom: 10px;*/

                  .node-name {
                    color: #575757;
                    background-color: #fff;
                    border-bottom: 1px solid #dee0e3;
                  }
                }

                .flow-item {

                  margin-top: 30px;
                }
              }
            }

            .after-branch-btn {
              padding: 20px 0 41px;
              position: relative;
              text-align: center;

              &::before {
                content: '';
                position: absolute;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                margin: auto;
                width: 2px;
                height: 100%;
                background-color: var(--star-horse-light-gray);
              }

              svg {
                cursor: pointer;
                z-index: 99999;
                position: relative;
              }
            }
          }

          .flow-end-box {
            padding-bottom: 120px;

            .flow-end {
              position: relative;
              display: -webkit-box;
              display: -ms-flexbox;
              display: flex;
              z-index: 2;
              -webkit-box-pack: center;
              -ms-flex-pack: center;
              justify-content: center;
              -webkit-box-align: center;
              -ms-flex-align: center;
              align-items: center;
              width: 120px;
              height: 40px;
              border-radius: 10px;
              color: #f8f8fa;
              background-image: -webkit-linear-gradient(120deg, #bbbbc4, #d5d5de), -webkit-linear-gradient(#bcbcc5, #bcbcc5);
              background-image: -o-linear-gradient(120deg, #bbbbc4 0, #d5d5de 100%), -o-linear-gradient(#bcbcc5, #bcbcc5);
              background-image: linear-gradient(-30deg, #bbbbc4, #d5d5de), linear-gradient(#bcbcc5, #bcbcc5);
              background-blend-mode: normal, normal;
              -webkit-box-shadow: 0 2px 10px 0 rgba(145, 145, 153, 50%);
              box-shadow: 0 2px 10px 0 rgba(145, 145, 153, 50%);
              font-size: 14px;
            }

            &:before {
              content: "";
              position: absolute;
              top: -14px;
              left: 50%;
              transform: translate(-50%);
              width: 10px;
              height: 10px;
              border-style: solid;
              border-radius: 50%;
              border-color: rgb(202, 202, 202) transparent transparent;
              background-color: var(--star-horse-light-gray);
            }
          }
        }
      }

      .sh-flow-editor-operate {
